package com.example.documentviewer;

import android.app.Activity;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.net.Uri;
import android.os.Bundle;
import android.util.Log;
import android.widget.ImageView;
import android.widget.TextView;
import android.widget.Toast;

import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

public class DocumentViewerActivity extends Activity {

    private static final String TAG = "DocumentViewerActivity";
    private static final Set<String> ALLOWED_MIME_TYPES = new HashSet<>(Arrays.asList(
            "application/pdf",
            "image/jpeg",
            "image/jpg",
            "image/png",
            "image/gif",
            "image/bmp",
            "image/webp"
    ));
    private static final Set<String> ALLOWED_SCHEMES = new HashSet<>(Arrays.asList(
            "content",
            "file"
    ));

    private TextView fileInfoTextView;
    private ImageView imageView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(createLayout());

        if (!validateIntent(getIntent())) {
            showError("Invalid or unauthorized request");
            finish();
            return;
        }

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        if (!validateIntent(intent)) {
            showError("Invalid or unauthorized request");
            finish();
            return;
        }
        handleIntent(intent);
    }

    private int createLayout() {
        android.widget.LinearLayout layout = new android.widget.LinearLayout(this);
        layout.setOrientation(android.widget.LinearLayout.VERTICAL);
        layout.setPadding(16, 16, 16, 16);

        fileInfoTextView = new TextView(this);
        fileInfoTextView.setTextSize(16);
        fileInfoTextView.setPadding(0, 0, 0, 20);
        layout.addView(fileInfoTextView);

        imageView = new ImageView(this);
        imageView.setAdjustViewBounds(true);
        layout.addView(imageView);

        return layout.getId();
    }

    private boolean validateIntent(Intent intent) {
        if (intent == null) {
            Log.w(TAG, "Null intent received");
            return false;
        }

        String action = intent.getAction();
        if (!Intent.ACTION_VIEW.equals(action)) {
            Log.w(TAG, "Invalid action: " + action);
            return false;
        }

        Uri uri = intent.getData();
        if (uri == null) {
            Log.w(TAG, "No URI provided in intent");
            return false;
        }

        if (!validateUri(uri)) {
            return false;
        }

        String mimeType = intent.getType();
        if (!validateMimeType(mimeType)) {
            return false;
        }

        if (!validateCallingPackage()) {
            return false;
        }

        return true;
    }

    private boolean validateUri(Uri uri) {
        if (uri == null) {
            Log.w(TAG, "URI is null");
            return false;
        }

        String scheme = uri.getScheme();
        if (scheme == null || !ALLOWED_SCHEMES.contains(scheme.toLowerCase())) {
            Log.w(TAG, "Invalid URI scheme: " + scheme);
            return false;
        }

        if ("content".equals(scheme)) {
            try {
                checkCallingOrSelfUriPermission(uri, Intent.FLAG_GRANT_READ_URI_PERMISSION);
            } catch (SecurityException e) {
                Log.w(TAG, "No permission to access URI: " + uri, e);
                return false;
            }
        }

        String path = uri.getPath();
        if (path != null && (path.contains("..") || path.contains("///"))) {
            Log.w(TAG, "Suspicious path detected: " + path);
            return false;
        }

        return true;
    }

    private boolean validateMimeType(String mimeType) {
        if (mimeType == null || mimeType.isEmpty()) {
            Log.w(TAG, "No MIME type provided");
            return false;
        }

        String normalizedMimeType = mimeType.toLowerCase().trim();
        if (!ALLOWED_MIME_TYPES.contains(normalizedMimeType)) {
            Log.w(TAG, "Unsupported MIME type: " + mimeType);
            return false;
        }

        return true;
    }

    private boolean validateCallingPackage() {
        String callingPackage = getCallingPackage();
        
        if (callingPackage == null) {
            int callingUid = getCallingUid();
            if (callingUid != getApplicationInfo().uid) {
                Log.w(TAG, "Unknown calling package with UID: " + callingUid);
            }
        }

        PackageManager pm = getPackageManager();
        if (callingPackage != null) {
            try {
                pm.getPackageInfo(callingPackage, 0);
                Log.d(TAG, "Request from package: " + callingPackage);
            } catch (PackageManager.NameNotFoundException e) {
                Log.w(TAG, "Calling package not found: " + callingPackage);
                return false;
            }
        }

        return true;
    }

    private int getCallingUid() {
        return android.os.Binder.getCallingUid();
    }

    private void handleIntent(Intent intent) {
        Uri uri = intent.getData();
        String mimeType = intent.getType();

        if (uri == null || mimeType == null) {
            showError("Invalid document data");
            return;
        }

        displayDocument(uri, mimeType);
    }

    private void displayDocument(Uri uri, String mimeType) {
        try {
            fileInfoTextView.setText("Document: " + uri.getLastPathSegment() + "\nType: " + mimeType);

            if (mimeType.startsWith("image/")) {
                displayImage(uri);
            } else if ("application/pdf".equals(mimeType)) {
                displayPdf(uri);
            }
        } catch (SecurityException e) {
            Log.e(TAG, "Security exception accessing document", e);
            showError("Access denied to document");
        } catch (Exception e) {
            Log.e(TAG, "Error displaying document", e);
            showError("Failed to open document");
        }
    }

    private void displayImage(Uri uri) {
        try {
            imageView.setImageURI(uri);
            imageView.setVisibility(android.view.View.VISIBLE);
        } catch (Exception e) {
            Log.e(TAG, "Error displaying image", e);
            showError("Failed to display image");
        }
    }

    private void displayPdf(Uri uri) {
        fileInfoTextView.append("\n\nPDF viewer not implemented in this example");
        imageView.setVisibility(android.view.View.GONE);
    }

    private void showError(String message) {
        Toast.makeText(this, message, Toast.LENGTH_LONG).show();
        Log.e(TAG, message);
    }
}